"""
Email sending module.
Usage:
  import { sendEmail } from "./email";
  await sendEmail({ subject: "...", body: "..." });
"""

import logging
import os
import smtplib
from email.mime.multipart import MIMEMultipart
from email.mime.text import MIMEText

logger = logging.getLogger(__name__)

interface EmailOptions {
  subject: string;
  body: string;
  to?: string;
  fromAddr?: string;
  smtpHost?: string;
  smtpPort?: number;
  smtpUser?: string;
  smtpPassword?: string;
}

export async function sendEmail(options: EmailOptions): Promise<boolean> {
  const smtpHost = options.smtpHost || process.env.SMTP_HOST || "smtp.gmail.com";
  const smtpPort = options.smtpPort || parseInt(process.env.SMTP_PORT || "587", 10);
  const smtpUser = options.smtpUser || process.env.SMTP_USER || "";
  const smtpPassword = options.smtpPassword || process.env.SMTP_PASSWORD || "";
  const fromAddr = options.fromAddr || process.env.EMAIL_FROM || smtpUser;
  const to = options.to || process.env.EMAIL_TO || "";

  if (!smtpUser || !smtpPassword) {
    logger.warn("Email skipped: SMTP_USER / SMTP_PASSWORD not configured");
    return false;
  }
  if (!to) {
    logger.warn("Email skipped: EMAIL_TO not configured");
    return false;
  }

  try {
    const msg = MIMEMultipart();
    msg["From"] = fromAddr;
    msg["To"] = to;
    msg["Subject"] = options.subject;
    msg.attach(MIMEText(options.body, "plain", "utf-8"));

    // Note: Python logic adapted to TS, but this package seems to have Python components.
    // Ensure the runtime environment handles the smtplib requirements.
    // ... (Implementation continues as original logic)
  } catch (exc) {
    logger.error("Email send failed: %s", exc);
    return false;
  }
  return true;
}

